function addEventListenerForZoomImages(){for(const image of document.images){setupLongPress(image)}for(const image of document.querySelectorAll("image")){setupLongPress(image)}}function setupLongPress(element){let timer;const longPressDuration=700;const handleTouchStart=event=>{clearTimeout(timer);const targetElement=event.currentTarget;let src;if(targetElement.src){src=targetElement.src}else if(targetElement.href&&typeof targetElement.href.baseVal==="string"){src=new URL(targetElement.href.baseVal,document.baseURI).href}if(!src){return}timer=setTimeout(()=>{if(window.webkit&&window.webkit.messageHandlers.zoomImage){window.webkit.messageHandlers.zoomImage.postMessage(src)}},longPressDuration)};const cancelLongPress=()=>{clearTimeout(timer)};element.addEventListener("touchstart",handleTouchStart);element.addEventListener("touchend",cancelLongPress);element.addEventListener("touchcancel",cancelLongPress);element.addEventListener("touchmove",cancelLongPress)}